-- 1. Sửa hàm fn_CalculateDeadline để tránh vòng lặp vô hạn khi OnboardDate là NULL
CREATE   FUNCTION [dbo].[fn_CalculateDeadline]
(
    @OnboardDate    DATE,
    @LeadTime       INT      -- Số ngày làm việc trước onboard
)
RETURNS DATE
AS
BEGIN
    -- Nếu @OnboardDate là NULL hoặc @LeadTime là NULL, trả về NULL ngay lập tức
    IF @OnboardDate IS NULL OR @LeadTime IS NULL
        RETURN NULL;

    DECLARE @Result DATE = @OnboardDate;
    DECLARE @DaysSubtracted INT = 0;

    -- Lùi ngược @LeadTime ngày làm việc (bỏ qua T7, CN)
    -- Giới hạn vòng lặp tối đa 100 lần để đề phòng mọi trường hợp treo
    WHILE @DaysSubtracted < @LeadTime AND @DaysSubtracted < 100
    BEGIN
        SET @Result = DATEADD(DAY, -1, @Result);
        -- Bỏ qua thứ 7 (7) và chủ nhật (1) trong DATEPART(WEEKDAY,...)
        -- DATEPART: 1=CN, 2=T2, 3=T3, 4=T4, 5=T5, 6=T6, 7=T7
        IF DATEPART(WEEKDAY, @Result) NOT IN (1, 7)
        BEGIN
            SET @DaysSubtracted = @DaysSubtracted + 1;
        END
    END

    RETURN @Result;
END;

CREATE FUNCTION [dbo].[fn_GenerateProjectId]
(
    @SubmitTimestamp    BIGINT,
    @CustomerName       NVARCHAR(200)
)
RETURNS NVARCHAR(100)
AS
BEGIN
    DECLARE @MaxId INT;

    -- Lấy giá trị Project_id lớn nhất hiện tại (chỉ lấy các ID là số nguyên)
    SELECT @MaxId = ISNULL(MAX(
        CASE 
            WHEN ISNUMERIC(Project_id) = 1 THEN CAST(Project_id AS INT)
            ELSE 0 
        END
    ), 0)
    FROM [dbo].[CSR_Projects];

    RETURN CAST(@MaxId + 1 AS NVARCHAR(100));
END

-- ============================================================
-- fn_GenerateTaskId
-- Tạo Task_id: <Project_id>_<Destination>_<TaskIndex>
-- ============================================================
CREATE   FUNCTION [dbo].[fn_GenerateTaskId]
(
    @ProjectId      NVARCHAR(100),
    @Destination    NVARCHAR(100),
    @TaskIndex      INT             -- Số thứ tự task trong project
)
RETURNS NVARCHAR(150)
AS
BEGIN
    DECLARE @DestAbbr NVARCHAR(20);
    SET @DestAbbr = UPPER(LEFT(REPLACE(@Destination, ' ', ''), 10));
    RETURN @ProjectId + '_' + @DestAbbr + '_' + RIGHT('000' + CAST(@TaskIndex AS NVARCHAR(3)), 3);
END

	CREATE PROCEDURE dbo.sp_alterdiagram
	(
		@diagramname 	sysname,
		@owner_id	int	= null,
		@version 	int,
		@definition 	varbinary(max)
	)
	WITH EXECUTE AS 'dbo'
	AS
	BEGIN
		set nocount on
	
		declare @theId 			int
		declare @retval 		int
		declare @IsDbo 			int
		
		declare @UIDFound 		int
		declare @DiagId			int
		declare @ShouldChangeUID	int
	
		if(@diagramname is null)
		begin
			RAISERROR ('Invalid ARG', 16, 1)
			return -1
		end
	
		execute as caller;
		select @theId = DATABASE_PRINCIPAL_ID();	 
		select @IsDbo = IS_MEMBER(N'db_owner'); 
		if(@owner_id is null)
			select @owner_id = @theId;
		revert;
	
		select @ShouldChangeUID = 0
		select @DiagId = diagram_id, @UIDFound = principal_id from dbo.sysdiagrams where principal_id = @owner_id and name = @diagramname 
		
		if(@DiagId IS NULL or (@IsDbo = 0 and @theId <> @UIDFound))
		begin
			RAISERROR ('Diagram does not exist or you do not have permission.', 16, 1);
			return -3
		end
	
		if(@IsDbo <> 0)
		begin
			if(@UIDFound is null or USER_NAME(@UIDFound) is null) -- invalid principal_id
			begin
				select @ShouldChangeUID = 1 ;
			end
		end

		-- update dds data			
		update dbo.sysdiagrams set definition = @definition where diagram_id = @DiagId ;

		-- change owner
		if(@ShouldChangeUID = 1)
			update dbo.sysdiagrams set principal_id = @theId where diagram_id = @DiagId ;

		-- update dds version
		if(@version is not null)
			update dbo.sysdiagrams set version = @version where diagram_id = @DiagId ;

		return 0
	END

CREATE PROCEDURE dbo.sp_creatediagram
(
	@diagramname 	sysname,
	@owner_id		int	= null, 	
	@version 		int,
	@definition 	varbinary(max)
)
WITH EXECUTE AS 'dbo'
AS
BEGIN
	set nocount on

	declare @theId int
	declare @retval int
	declare @IsDbo	int
	declare @userName sysname
	if(@version is null or @diagramname is null)
	begin
		RAISERROR (N'E_INVALIDARG', 16, 1);
		return -1
	end

	execute as caller;
	select @theId = DATABASE_PRINCIPAL_ID(); 
	select @IsDbo = IS_MEMBER(N'db_owner');
	revert; 
	
	if @owner_id is null
	begin
		select @owner_id = @theId;
	end
	else
	begin
		if @theId <> @owner_id
		begin
			if @IsDbo = 0
			begin
				RAISERROR (N'E_INVALIDARG', 16, 1);
				return -1
			end
			select @theId = @owner_id
		end
	end
	-- next 2 line only for test, will be removed after define name unique
	if EXISTS(select diagram_id from dbo.sysdiagrams where principal_id = @theId and name = @diagramname)
	begin
		RAISERROR ('The name is already used.', 16, 1);
		return -2
	end

	insert into dbo.sysdiagrams(name, principal_id , version, definition)
			VALUES(@diagramname, @theId, @version, @definition) ;
	
	select @retval = @@IDENTITY 
	return @retval
END

CREATE PROCEDURE dbo.sp_dropdiagram
(
	@diagramname 	sysname,
	@owner_id	int	= null
)
WITH EXECUTE AS 'dbo'
AS
BEGIN
	set nocount on
	declare @theId 			int
	declare @IsDbo 			int
	
	declare @UIDFound 		int
	declare @DiagId			int

	if(@diagramname is null)
	begin
		RAISERROR ('Invalid value', 16, 1);
		return -1
	end

	EXECUTE AS CALLER;
	select @theId = DATABASE_PRINCIPAL_ID();
	select @IsDbo = IS_MEMBER(N'db_owner'); 
	if(@owner_id is null)
		select @owner_id = @theId;
	REVERT; 
	
	select @DiagId = diagram_id, @UIDFound = principal_id from dbo.sysdiagrams where principal_id = @owner_id and name = @diagramname 
	if(@DiagId IS NULL or (@IsDbo = 0 and @UIDFound <> @theId))
	begin
		RAISERROR ('Diagram does not exist or you do not have permission.', 16, 1)
		return -3
	end

	delete from dbo.sysdiagrams where diagram_id = @DiagId;

	return 0;
END

	CREATE PROCEDURE dbo.sp_helpdiagramdefinition
	(
		@diagramname 	sysname,
		@owner_id	int	= null 		
	)
	WITH EXECUTE AS N'dbo'
	AS
	BEGIN
		set nocount on

		declare @theId 		int
		declare @IsDbo 		int
		declare @DiagId		int
		declare @UIDFound	int
	
		if(@diagramname is null)
		begin
			RAISERROR (N'E_INVALIDARG', 16, 1);
			return -1
		end
	
		execute as caller;
		select @theId = DATABASE_PRINCIPAL_ID();
		select @IsDbo = IS_MEMBER(N'db_owner');
		if(@owner_id is null)
			select @owner_id = @theId;
		revert; 
	
		select @DiagId = diagram_id, @UIDFound = principal_id from dbo.sysdiagrams where principal_id = @owner_id and name = @diagramname;
		if(@DiagId IS NULL or (@IsDbo = 0 and @UIDFound <> @theId ))
		begin
			RAISERROR ('Diagram does not exist or you do not have permission.', 16, 1);
			return -3
		end

		select version, definition FROM dbo.sysdiagrams where diagram_id = @DiagId ; 
		return 0
	END

CREATE PROCEDURE dbo.sp_renamediagram
(
	@diagramname 		sysname,
	@owner_id		int	= null,
	@new_diagramname	sysname

)
WITH EXECUTE AS 'dbo'
AS
BEGIN
	set nocount on
	declare @theId 			int
	declare @IsDbo 			int
	
	declare @UIDFound 		int
	declare @DiagId			int
	declare @DiagIdTarg		int
	declare @u_name			sysname
	if((@diagramname is null) or (@new_diagramname is null))
	begin
		RAISERROR ('Invalid value', 16, 1);
		return -1
	end

	EXECUTE AS CALLER;
	select @theId = DATABASE_PRINCIPAL_ID();
	select @IsDbo = IS_MEMBER(N'db_owner'); 
	if(@owner_id is null)
		select @owner_id = @theId;
	REVERT;

	select @u_name = USER_NAME(@owner_id)

	select @DiagId = diagram_id, @UIDFound = principal_id from dbo.sysdiagrams where principal_id = @owner_id and name = @diagramname 
	if(@DiagId IS NULL or (@IsDbo = 0 and @UIDFound <> @theId))
	begin
		RAISERROR ('Diagram does not exist or you do not have permission.', 16, 1)
		return -3
	end

	-- if((@u_name is not null) and (@new_diagramname = @diagramname))	-- nothing will change
	--	return 0;

	if(@u_name is null)
		select @DiagIdTarg = diagram_id from dbo.sysdiagrams where principal_id = @theId and name = @new_diagramname
	else
		select @DiagIdTarg = diagram_id from dbo.sysdiagrams where principal_id = @owner_id and name = @new_diagramname

	if((@DiagIdTarg is not null) and  @DiagId <> @DiagIdTarg)
	begin
		RAISERROR ('The name is already used.', 16, 1);
		return -2
	end		

	if(@u_name is null)
		update dbo.sysdiagrams set [name] = @new_diagramname, principal_id = @theId where diagram_id = @DiagId
	else
		update dbo.sysdiagrams set [name] = @new_diagramname where diagram_id = @DiagId
	return 0
END

CREATE PROCEDURE [dbo].[usp_AddAuditLog]
