CREATE   PROCEDURE [dbo].[usp_SearchEmployees]
    @Query      NVARCHAR(200) = '',
    @TopN       INT = 20
AS
BEGIN
    SET NOCOUNT ON;
    SELECT TOP (@TopN)
        [FullName], [Email], [MNV]
